// functions/api/hello.js  ->  GET/POST /api/hello
export async function onRequest(context) {
  // context.env carries your bindings (DB, CACHE) + vars + secrets
  const { env } = context;

  // Read one row from the D1 database bound as DB
  const { results } = await env.DB
    .prepare("SELECT name FROM greetings WHERE id = ?")
    .bind(1)
    .all();
  const name = results[0]?.name ?? "world";

  // Count visits in the KV namespace bound as CACHE
  const hits = Number(await env.CACHE.get("hits")) + 1;
  await env.CACHE.put("hits", String(hits));

  return Response.json({ message: `Hello from ${name}!`, hits });
}

-- schema.sql: create the table the Function reads, then seed one row
CREATE TABLE IF NOT EXISTS greetings (
  id   INTEGER PRIMARY KEY,
  name TEXT NOT NULL
);

INSERT INTO greetings (id, name) VALUES (1, 'Taipei');
